// Or custom patrol with waypoints:
class PatrolEnemy {
  sprite: Phaser.Physics.Arcade.Sprite;
  speed = 100;
  direction = 1;
  leftBound: number;
  rightBound: number;

  constructor(scene: Phaser.Scene, x: number, y: number, range: number) {
    this.sprite = scene.physics.add.sprite(x, y, "enemy");
    this.leftBound = x - range;
    this.rightBound = x + range;
  }

  update() {
    this.sprite.body!.setVelocityX(this.speed * this.direction);
    if (this.sprite.x >= this.rightBound) this.direction = -1;
    if (this.sprite.x <= this.leftBound) this.direction = 1;
    this.sprite.setFlipX(this.direction < 0);
  }
}

