// Simple dialog box
class DialogBox {
  private bg: Phaser.GameObjects.Graphics;
  private text: Phaser.GameObjects.Text;
  private lines: string[];
  private index = 0;

  constructor(private scene: Phaser.Scene) {
    const { width, height } = scene.scale;
    this.bg = scene.add.graphics().setScrollFactor(0).setDepth(200);
    this.bg.fillStyle(0x000000, 0.8);
    this.bg.fillRoundedRect(20, height - 120, width - 40, 100, 8);
    this.text = scene.add.text(40, height - 110, "", {
      fontSize: "16px", color: "#fff", wordWrap: { width: width - 80 }
    }).setScrollFactor(0).setDepth(201);
    this.lines = [];
    this.hide();
  }

  show(lines: string[]) {
    this.lines = lines; this.index = 0;
    this.bg.setVisible(true); this.text.setVisible(true);
    this.text.setText(this.lines[0]);
  }

  next(): boolean {
    this.index++;
    if (this.index >= this.lines.length) { this.hide(); return false; }
    this.text.setText(this.lines[this.index]);
    return true;
  }

  hide() { this.bg.setVisible(false); this.text.setVisible(false); }
}

// Simple grid setup
const COLS = 6;
const ROWS = 8;
const CELL = 64;
const OFFSET_X = 100;
const OFFSET_Y = 50;
const grid: (Phaser.GameObjects.Sprite | null)[][] = [];
const colors = ["red", "blue", "green", "yellow"];

for (let r = 0; r < ROWS; r++) {
  grid[r] = [];
  for (let c = 0; c < COLS; c++) {
    const color = Phaser.Utils.Array.GetRandom(colors);
    const x = OFFSET_X + c * CELL + CELL / 2;
    const y = OFFSET_Y + r * CELL + CELL / 2;
    const gem = this.add.sprite(x, y, color).setInteractive();
    gem.setData({ row: r, col: c, color });
    grid[r][c] = gem;
  }
}

